// US AQI from PM2.5 (simplified breakpoints)
function aqiFromPm(pm) {
    const bp = [[0,12,0,50],[12.1,35.4,51,100],[35.5,55.4,101,150],[55.5,150.4,151,200]];
    for (const [cl, ch, il, ih] of bp) {
        if (pm <= ch) return Math.round((ih - il) / (ch - cl) * (pm - cl) + il);
    }
    return 250;
}

const d = msg.payload;
const aqi = aqiFromPm(d.pm25);
const alerts = [];

if (d.temperature >= 31) alerts.push({ level: 'critical', metric: 'temperature', message: d.temperature + 'C exceeds 31C threshold' });
if (aqi > 50)            alerts.push({ level: 'warning',  metric: 'air',         message: 'AQI ' + aqi + ' degrading' });
if (d.humidity < 40)     alerts.push({ level: 'info',     metric: 'humidity',    message: d.humidity + '% below comfort range' });

if (alerts.length === 0) return null;
msg.payload = { ts: d.ts, aqi: aqi, alerts: alerts };
return msg;
